
-- Create events table (mirrors restaurants pattern)
CREATE TABLE public.events (
  id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  event_name TEXT NOT NULL,
  event_url TEXT NOT NULL,
  category TEXT NOT NULL DEFAULT 'Experience',
  location TEXT NOT NULL DEFAULT 'Walt Disney World',
  location_type TEXT NOT NULL DEFAULT 'Park',
  area TEXT,
  description TEXT,
  price_info TEXT,
  requires_reservation BOOLEAN DEFAULT true,
  is_active BOOLEAN DEFAULT true,
  created_at TIMESTAMP WITH TIME ZONE DEFAULT now(),
  updated_at TIMESTAMP WITH TIME ZONE DEFAULT now()
);

ALTER TABLE public.events ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Authenticated users can view events"
ON public.events FOR SELECT TO authenticated USING (true);

